// src/SiparisIslemleri/SiparisOlustur.js
import React, { useMemo, useState } from "react";
import { Download, Link as LinkIcon, ListChecks, IdCard, FileSpreadsheet } from "lucide-react";
import * as XLSX from "xlsx";
import "./SiparisOlustur.css"; // ✅ yeni CSS

const HEADERS = [
    "Müşteri VKN", "Müşteri Unvan", "Hizmet Tipi", "Proje Adı", "Sipariş Tarihi", "Yükleme Tarihi", "Teslim Tarihi",
    "Müşteri Siparis No", "Müşteri Referans No", "İstenilen Araç Tipi", "Açıklama", "Yükleme Noktası", "Yükleme İli",
    "Yükleme İlçesi", "Yükleme Yeri", "Alıcı Firma", "Teslim Noktası", "Teslim İli", "Teslim İlçesi", "Teslim Yeri",
    "İrsaliye No", "İrsaliye Miktar", "Ürün", "Kap Adet", "Ambalaj Tipi", "Brüt KG", "M3", "Desi",
];

const emptyRow = () => HEADERS.reduce((acc, key) => ({ ...acc, [key]: "" }), {});

export default function SiparisOlustur() {
    const [projeAdi, setProjeAdi] = useState("");
    const [rows, setRows] = useState([emptyRow()]);
    const columns = useMemo(() => HEADERS, []);

    const handleTemplateDownload = () => {
        const wsData = [columns, ...[emptyRow()].map((r) => columns.map((c) => r[c] ?? ""))];
        const ws = XLSX.utils.aoa_to_sheet(wsData);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Sablon");
        XLSX.writeFile(wb, `Siparis_Sablon_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const handleExportExcel = () => {
        const data = rows.map((r) => {
            const obj = {};
            columns.forEach((c) => (obj[c] = r[c] ?? ""));
            return obj;
        });
        const ws = XLSX.utils.json_to_sheet(data, { header: columns });
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Siparisler");
        XLSX.writeFile(wb, `Siparisler_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const handleEslesmeYap = () => {
        alert("Eşleşme işlemi tetiklendi (buraya API entegrasyonu bağlanacak).");
    };

    const handleEslesmeIdGetir = () => {
        const fakeId = Math.random().toString(36).slice(2, 10).toUpperCase();
        alert(`Eşleşme ID'si: ${fakeId}\n(Not: Servis entegrasyonu ile değiştirin)`);
    };

    const addRow = () => setRows((r) => [...r, emptyRow()]);
    const removeRow = (idx) => setRows((r) => r.filter((_, i) => i !== idx));
    const updateCell = (idx, key, value) =>
        setRows((r) => r.map((row, i) => (i === idx ? { ...row, [key]: value } : row)));

    return (
        <div className="so-page">
            <div className="so-header">
                <div>
                    <h1 className="so-title">Sipariş Oluştur</h1>
                    <div className="so-subtitle">SiparisOlustur.js</div>
                </div>
            </div>

            <div className="so-grid">
                <div className="so-card">
                    <label className="so-label">Proje Adı</label>
                    <select className="so-input" value={projeAdi} onChange={(e) => setProjeAdi(e.target.value)}>
                        <option value="">Seçiniz</option>
                        <option>Proje A</option>
                        <option>Proje B</option>
                        <option>Proje C</option>
                    </select>
                    <p className="so-help">Projeyi seçtiğinizde tabloda “Proje Adı” alanı hızlı doldurulur.</p>
                </div>

                <div className="so-card so-actions">
                    <button className="so-btn so-btn-primary" onClick={handleTemplateDownload}>
                        <Download size={18} /> Şablonu İndir
                    </button>
                    <button className="so-btn" onClick={handleEslesmeYap}>
                        <LinkIcon size={18} /> Eşleşme Yap
                    </button>
                    <button className="so-btn" onClick={handleEslesmeIdGetir}>
                        <IdCard size={18} /> Eşleşme ID’lerini Getir
                    </button>
                    <button className="so-btn" onClick={handleExportExcel}>
                        <FileSpreadsheet size={18} /> Dışarı Excel Aktarma
                    </button>
                </div>

                <div className="so-card">
                    <div className="so-inline-actions">
                        <button className="so-btn" onClick={addRow}>Satır Ekle</button>
                        <button className="so-btn" onClick={() => setRows([emptyRow()])}>Şablonu Sıfırla</button>
                    </div>
                    <p className="so-help">Tabloda satır ekleyebilir ya da şablonu başlangıç haline döndürebilirsiniz.</p>
                </div>
            </div>

            <div className="so-table-card">
                <div className="so-table-header">
                    <ListChecks size={18} /> <span>Şablon</span>
                    <span className="so-table-sub">(İndirilen şablon ile başlıklar birebir uyumlu)</span>
                </div>

                <div className="so-table-wrap">
                    <table className="so-table">
                        <thead>
                            <tr>
                                <th className="so-index">#</th>
                                {columns.map((c) => <th key={c}>{c}</th>)}
                                <th>İşlem</th>
                            </tr>
                        </thead>
                        <tbody>
                            {rows.map((row, rowIdx) => (
                                <tr key={rowIdx}>
                                    <td className="so-index">{rowIdx + 1}</td>
                                    {columns.map((col) => (
                                        <td key={`${rowIdx}-${col}`}>
                                            <input
                                                className="so-cell-input"
                                                value={col === "Proje Adı" && !row[col] && projeAdi ? projeAdi : row[col]}
                                                onChange={(e) => updateCell(rowIdx, col, e.target.value)}
                                                placeholder={col}
                                            />
                                        </td>
                                    ))}
                                    <td>
                                        <button className="so-btn so-btn-danger" onClick={() => removeRow(rowIdx)}>Sil</button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
                <div className="so-footnote">
                    İpucu: “Şablonu İndir” ile oluşturulan Excel, bu tabloda gördüğünüz başlıklarla uyumludur.
                </div>
            </div>
        </div>
    );
}
